"""
MKT Christ-in-Every-Verse Commentary — Genesis chapters 36–37
Run: python3 scripts/zc-christ-genesis-36-37.py

Source data used:
- data/interlinear/genesis.json
- data/translation/draft/mediating/genesis.json (MKT text)
- data/commentary/mkt-christ/genesis.json (v28 of ch37 pre-existing)

Key Christological decisions:
- Ch36 (Edomite genealogy/chiefs/kings) is treated through the lens of election
  theology. Edom is the rejected line (Jacob loved, Esau hated — Mal 1:2-3 /
  Rom 9:13); the chapter closes out Esau's narrative so the rest of Genesis can
  follow the elect line of Jacob. The Edomite kings list (vv31-39) is read as
  the foil to the coming Davidic/messianic kingship. Herod the Great (an Idumean/
  Edomite) is the ironic culmination: the last "king of Edom" sought to destroy
  the true King of Israel (Matt 2:1-18). Individual genealogy verses receive
  brief entries anchored in the general framework; the chapter as a whole is
  important for what it marks — the closing of Esau's line before Joseph's story.
- Ch37 is one of the richest OT chapters for Christ typology. Joseph is the
  greatest OT type of Christ — the beloved son sent by his father to his
  brothers, rejected, sold by one of his brothers (Judah/Judas), thrown into
  a pit/cistern, and descending into Egypt (humiliation) before the exaltation
  that saves his family and the world.
- Key NT connections: father sending son to brothers = John 3:16/Heb 1:2;
  robe of distinction = kingly dignity stripped before execution (John 19:23);
  brothers' causeless hatred = John 15:25; "come, let's kill him and take his
  inheritance" = Matt 21:38 (parable of wicked tenants); cistern = empty tomb
  (the place where he was thrown is found empty); 20 pieces of silver = betrayal
  price (upgraded to 30 for Jesus, Zech 11:12-13); Judah proposes the sale =
  Judas (same name family) betrays Jesus; bloody robe = false evidence / the
  evidence that "proves" the wrong story; Jacob's unendable grief = the grief
  that the resurrection overturns.
- v28 already exists in the output file; merge_comm will skip it.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-christ commentary for Genesis 36–37: the Edomite genealogy that
#   closes out the rejected line, and Joseph's descent into Egypt — the greatest
#   OT type of Christ (beloved son, rejected, sold, humiliated, then exalted
#   as savior of the world).
# CHANGE? If data/commentary/mkt-christ/genesis.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-christ/genesis.json')); print(len(d.get('36',{})), len(d.get('37',{})))" should print "43 36".

NEW_DATA = {
"36": {
"1": "<p>&#8220;This is the account of the family line of Esau (that is, Edom).&#8221; The <em>toledot</em> formula &#8212; the same structure that frames every major genealogy in Genesis &#8212; is given to Esau&#8217;s line. But unlike the <em>toledot</em> of Jacob (37:2), which opens into the great Joseph narrative, Esau&#8217;s <em>toledot</em> is genealogy and closure. The chapter exists to account for Esau&#8217;s line and close it out, so that what follows in Genesis tracks only the covenant line. Election is real exclusion as well as real inclusion: God&#8217;s choice of Jacob is not arbitrary but purposive, and the closing of Esau&#8217;s narrative in ch36 is the narrative form of that exclusion. Rom 9:13 &#8212; &#8220;Jacob I loved, but Esau I hated&#8221; &#8212; is the theological summary of the movement from ch36 to ch37.</p>",
"2": "<p>Esau&#8217;s wives from Canaan &#8212; contrary to the explicit guidance that defined the covenant line (24:3; 28:1). The first note about Esau&#8217;s descendants marks the non-covenant character of his line: he marries those from whom the covenant people were to remain distinct. The covenant identity is not primarily ethnic but covenant-relational &#8212; defined by faithfulness to the God of the promise. Esau&#8217;s Canaanite wives are the first signal that his line will follow a different path. The contrast with Jacob, who sought wives from within the covenant family (ch28-29), marks the two lines apart from the beginning.</p>",
"3": "<p>Basemath, daughter of Ishmael &#8212; Esau marries within the other rejected line (Ishmael was excluded from the primary covenant inheritance, though blessed). The rejected lines intermingle: Esau&#8217;s Ishmaelite wife produces a branch of his genealogy. Both Ishmael and Esau received divine blessings &#8212; Ishmael became a great nation (21:18), Esau received the prosperity described in this chapter &#8212; but neither received the covenant promise of the seed through whom all nations would be blessed. The distinction between temporal blessing and covenant election runs throughout Genesis and finds its NT culmination in the one who is both the fulfillment of the covenant and the blessing of all nations (Gal 3:16, 29).</p>",
"4": "<p>Eliphaz and Reuel &#8212; the two major lines of Esau&#8217;s descendants through Adah and Basemath. Eliphaz is the name of the first and wisest of Job&#8217;s three friends (Job 2:11) &#8212; a Temanite (v15), which matches this genealogy. The wisdom of Edom (Jer 49:7 &#8212; &#8220;Is there no longer wisdom in Teman?&#8221;) is well attested; the Edomites had a wisdom tradition that ran parallel to Israel&#8217;s. The general revelation available to all people (Rom 1:20) means that wisdom is not confined to the covenant people &#8212; but the covenant people receive the special revelation that alone leads to salvation (Rom 10:14-17). Christ is &#8220;the wisdom of God&#8221; (1 Cor 1:24) that both fulfills and surpasses the wisdom of Edom.</p>",
"5": "<p>The sons born to Esau in Canaan before the move to Seir &#8212; Jeush, Jalam, and Korah. The family established in the land of promise, then leaving. The irony of Esau settling in Canaan and then departing, while Jacob returns to Canaan and settles: the land of promise is for the covenant heir, not the rejected line. The motif of the wrong person in the right place is corrected by the movement of history: Esau leaves; Jacob remains. The covenant people&#8217;s attachment to the promised land is not merely ethnic or geographic but theological &#8212; it points toward the new creation and the city that is to come (Heb 11:10; Rev 21:2).</p>",
"6": "<p>Esau took all his household, livestock, and possessions accumulated in Canaan and moved to a land away from his brother Jacob. The separation of the two brothers &#8212; the elect and the non-elect &#8212; through the natural mechanism of insufficient grazing land (v7). Divine providence operates through mundane economic pressures to accomplish the separation that the covenant structure requires. The God who chose Jacob over Esau does not need supernatural intervention to accomplish the separation; the ordinary pressures of pastoral life suffice. The separation serves the covenant: Jacob must inhabit Canaan; Esau must be elsewhere. Providence is often quiet.</p>",
"7": "<p>&#8220;Their possessions had become too great for them to remain together; the land where they were staying could not support them.&#8221; The same dynamic separated Abraham and Lot (13:6): the covenant land requires its people to separate from the non-covenant people as blessing accumulates. Lot chose Sodom; Esau chooses Seir. In both cases, the separation that looks economically motivated is actually covenantally necessary: the covenant heir must have the land. The &#8220;too great to remain together&#8221; language echoes the later Exodus concern (Exod 1:9 &#8212; &#8220;the Israelites have become far too numerous for us&#8221;). Blessing multiplies until separation becomes necessary.</p>",
"8": "<p>Esau settled in the hill country of Seir &#8212; he is Edom, he is there. The geographical establishment of Edom in Seir closes the first movement of the chapter. Seir is the mountain country southeast of Canaan that becomes Edom&#8217;s permanent territory. The Edomites and Israelites will be in conflict throughout the historical books: Saul fights Edom (1 Sam 14:47), David subdues Edom (2 Sam 8:14), Edom revolts against Jehoshaphat (2 Kgs 8:20). The hostility between brothers that begins in the womb (25:22-23) takes geographical form here. The NT resolution: &#8220;there is neither Jew nor Gentile&#8230; you are all one in Christ Jesus&#8221; (Gal 3:28) &#8212; the covenant-versus-non-covenant division is overcome in Christ.</p>",
"9": "<p>The second <em>toledot</em> heading within the chapter &#8212; &#8220;the account of Esau the father of the Edomites.&#8221; The doubled introduction signals that ch36 is a comprehensive genealogical record of Esau&#8217;s legacy, not a narrative episode. The thoroughness of the record shows that God keeps account of all nations, not only Israel. Acts 17:26 &#8212; &#8220;from one man he made all the nations, that they should inhabit the whole earth; and he marked out their appointed times in history and the boundaries of their lands.&#8221; The Edomite genealogy is the form of that divine ordering of the nations. God&#8217;s sovereignty extends to the table of nations, not only to the covenant community.</p>",
"10": "<p>Eliphaz son of Adah and Reuel son of Basemath &#8212; the two main branches of Esau&#8217;s line through his wives. The genealogical record of the rejected brother is preserved in Scripture alongside the covenant genealogy of Jacob. This preservation is itself a form of grace: Esau is not erased but remembered. The God who chose Jacob did not annihilate Esau &#8212; he blessed him with many descendants and territory, in fulfillment of the blessing Isaac gave (27:39-40). The non-elect are not abandoned by God; they receive the blessings of common grace. Christ&#8217;s atonement is sufficient for all, though effective for the elect (1 John 2:2 &#8212; &#8220;the atoning sacrifice for our sins, and not only for ours but also for the sins of the whole world&#8221;).</p>",
"11": "<p>The sons of Eliphaz: Teman, Omar, Zepho, Gatam, and Kenaz. Teman is the most prominent &#8212; a city in Edom famous for its wisdom (Jer 49:7; Amos 1:12). Eliphaz the Temanite of Job 2:11 carries the wisdom of this region. The &#8220;wisdom of the east&#8221; that the magi represent (Matt 2:1) is part of the general revelation that God dispersed among the nations. The magi&#8217;s wisdom ultimately led them to Christ &#8212; the wisdom that Edom had without the covenant was insufficient without the covenant people&#8217;s scripture and the star of Bethlehem. All human wisdom finds its goal in Christ (Col 2:3 &#8212; &#8220;in whom are hidden all the treasures of wisdom and knowledge&#8221;).</p>",
"12": "<p>Timna was a concubine of Eliphaz, who bore him Amalek. Amalek &#8212; the people who became Israel&#8217;s perennial enemy, attacking from behind (Deut 25:17-18), whom God commanded to be blotted out (1 Sam 15). The Amalekite lineage that begins here becomes the line of Haman the Agagite (Esth 3:1 &#8212; Agag was the Amalekite king of 1 Sam 15) who seeks to destroy all the Jews in Persia. The spiritual pattern of the enemy who attacks the weak and pursues the covenant community across history is the pattern that culminates in the dragon who seeks to devour the woman&#8217;s child (Rev 12:4). Every Amalek points toward the final enemy that Christ defeats (Rev 20:10).</p>",
"13": "<p>The sons of Reuel: Nahath, Zerah, Shammah, and Mizzah. Reuel is also the name of Moses&#8217; father-in-law (Exod 2:18) &#8212; an Edomite/Midianite connection. The interweaving of the covenant history with Edomite family names is a reminder that God&#8217;s saving purposes are not sealed in a hermetic ethnic enclosure. Moses&#8217; connections to Midian/Edom are part of his formation; the wisdom and hospitality of Jethro (another name for Reuel) are gifts that God uses within his providential plan. The covenant community is always entangled with the nations around it &#8212; and Christ is the one in whom all entanglements are redeemed (Eph 1:10 &#8212; &#8220;to bring unity to all things in heaven and on earth under Christ&#8221;).</p>",
"14": "<p>The sons of Oholibamah: Jeush, Jalam, and Korah. Korah is also the name of the Levitical rebel (Num 16:1) who led the revolt against Moses and Aaron &#8212; different person, same name. The recurrence of names across covenant and non-covenant lines is a reminder that the human family is one family. The rebellion pattern is not exclusive to the non-covenant nations; the covenant people are equally capable of the Korah-style revolt against divinely appointed leadership. The NT warning about following Korah&#8217;s example (Jude 11) is addressed to the church. Sin and rebellion are human problems, not merely Edomite ones. Christ alone is the one who does not rebel but fulfills (Matt 5:17).</p>",
"15": "<p>The chiefs among Esau&#8217;s descendants through Eliphaz. The listing of chiefs (<em>ʾallûfîm</em>) &#8212; the organizational structure of Edomite tribal society. The political organization of the nations is God&#8217;s provision for human order after the Fall: the structures of authority that restrain chaos are part of common grace. Rom 13:1 &#8212; &#8220;the governing authorities that exist have been established by God.&#8221; The Edomite chiefs represent the human authority structures that God permits and orders &#8212; not covenant mediators, but providential organizers of human community. Christ is the one in whom all legitimate authority is grounded (Col 1:16 &#8212; &#8220;all things were created through him and for him&#8221;) and to whom all authority will be submitted (1 Cor 15:25).</p>",
"16": "<p>Chief Korah, Chief Gatam, and Chief Amalek among the Edomite chiefs. The listing of Amalek as a chief in Edom formalizes what v12 introduced: Amalek is a recognized political entity within Edomite society. The national enemies of Israel are not random &#8212; they have genealogical, political, and historical identities. The enemy that attacks the covenant community is a real, organized entity. The NT equivalent is not a tribal confederation but spiritual powers (Eph 6:12 &#8212; &#8220;our struggle is not against flesh and blood, but against the rulers, against the authorities, against the powers of this dark world&#8221;). Christ has disarmed these powers (Col 2:15) and his final victory will end the enmity that began in the womb (25:22-23).</p>",
"17": "<p>Chiefs descended from Reuel &#8212; Nahath, Zerah, Shammah, and Mizzah &#8212; all Edomite chiefs. The comprehensive listing shows that God&#8217;s ordering of the nations is thorough &#8212; not only the covenant people are organized under his providence, but also the nations that surround them. The sheer completeness of the Edomite record points to the divine care that extends even to those outside the covenant. Acts 14:17 &#8212; &#8220;he has not left himself without testimony: he has shown kindness by giving you rain from heaven and crops in their seasons.&#8221; The Edomite chiefs receive the common grace of political organization, agricultural provision, and territorial settlement &#8212; all from the God of Israel, whether they acknowledge him or not.</p>",
"18": "<p>Chiefs descended from Oholibamah &#8212; Jeush, Jalam, and Korah. The three chiefs through Esau&#8217;s third wife complete the enumeration of Edomite leadership. The third wife&#8217;s descendants receiving the same dignified enumeration as the others reflects the biblical pattern of comprehensive accounting: no branch of the human family is beneath divine notice. The parable of the lost sheep (Luke 15:4-7) &#8212; leaving ninety-nine to find the one &#8212; operates on the assumption that every individual counts. The Edomite genealogy is the covenant God&#8217;s comprehensive accounting of the human family, even the line that did not receive the covenant promise.</p>",
"19": "<p>&#8220;These were the sons of Esau (that is, Edom), and these were their chiefs.&#8221; The summary that closes the enumeration of Esau&#8217;s immediate descendants and chiefs. The Esau/Edom identification &#8212; repeated through the chapter &#8212; is the narrative equivalent of the divine word &#8220;Esau I hated&#8221; (Mal 1:3). Edom is the name that history gives to the rejected line; the name encodes the rejection while preserving the person. Jacob becomes Israel &#8212; the covenant name replaces the birth name. Esau becomes Edom &#8212; the ethnic name replaces the personal name. The rejected line endures under its own identity, outside the covenant. The elect line is transformed by the covenant encounter. Christ is the one through whom Jacob&#8217;s transformation becomes available to Edomites (Gal 3:28).</p>",
"20": "<p>The Horites &#8212; the original inhabitants of the Seir hill country before Esau&#8217;s line displaced them. Deut 2:12 notes that &#8220;the Horites used to live in Seir, but the descendants of Esau drove them out.&#8221; Esau&#8217;s line displaces the Horites just as the Israelites will displace the Canaanites &#8212; the same pattern at a smaller scale, without covenant justification. The Horite genealogy that follows (vv20-30) is included because Esau&#8217;s family intermarried with the Horites (Oholibamah was a Horite, vv2, 14). The entanglement of the elected Edomites with the Horite indigenous population reflects the complex social realities through which divine providence works. No human community exists in pure isolation.</p>",
"21": "<p>The Horite chiefs: Lotan, Shobal, Zibeon, Anah, Dishon, Ezer, and Dishan. The indigenous people of Seir receive their own genealogical accounting &#8212; they are not merely the unnamed background against which Esau&#8217;s arrival is staged. The biblical pattern of including the genealogies of displaced peoples (the Horites here, the table of nations in ch10) reflects the covenant God&#8217;s comprehensive interest in all human communities. Christ died for Horites as well as Israelites &#8212; the &#8220;every tribe, language, people and nation&#8221; of Rev 5:9 includes peoples long absorbed and forgotten by history but not by God.</p>",
"22": "<p>Lotan&#8217;s sons: Hori and Homam. Timna was Lotan&#8217;s sister &#8212; the same Timna who became Eliphaz&#8217;s concubine (v12) and bore Amalek. The genealogical link between the Horites and Edomites through Timna shows the social integration of the two groups. The covenant community&#8217;s own genealogy includes similar entanglements: Tamar (ch38), Ruth (a Moabite), Rahab (a Canaanite), and Bathsheba (wife of a Hittite) all appear in Matthew&#8217;s genealogy of Christ (Matt 1:2-16). The genealogy of the Messiah includes the outsider precisely because Christ&#8217;s mission is to bring the outsider in. The Horite connections in Esau&#8217;s genealogy are the dark mirror of the Gentile connections in Jesus&#8217; genealogy.</p>",
"23": "<p>The sons of Shobal: Alvan, Manahath, Ebal, Shepho, and Onam. The Horite genealogy continues with the thoroughness that the text gives to all genealogical records &#8212; a thoroughness that reflects the biblical conviction that human identity is located in family, ancestry, and community. The Horites are not nameless masses; they are individuals with specific family lines. This specificity is the form of biblical anthropology: people are known in their particularity, not as abstract humanity. Christ himself entered human particularity &#8212; born of a specific woman, in a specific town, of a specific lineage (Matt 1:1). The incarnation is the ultimate affirmation of human particularity as the location of divine encounter.</p>",
"24": "<p>Zibeon&#8217;s sons: Aiah and Anah. &#8220;This is the Anah who discovered the hot springs in the desert while he was grazing the donkeys of his father Zibeon.&#8221; The parenthetical note &#8212; a single act of discovery preserved in the genealogy. The springs (<em>yemim</em> &#8212; possibly &#8220;mules&#8221; or &#8220;hot springs&#8221; &#8212; the word is uncertain) are the one thing Anah is remembered for. The genealogy of the nations preserves small acts alongside great ones. Every human life has moments that define its place in the larger story. Christ entered a world where Anah&#8217;s springs had been flowing for centuries &#8212; a world with deep, specific history in every direction, not a blank stage for salvation history to play out upon.</p>",
"25": "<p>Anah&#8217;s children: Dishon and Oholibamah daughter of Anah. Oholibamah &#8212; one of Esau&#8217;s wives (v2) &#8212; is identified as a granddaughter of Zibeon through Anah. The family connections that make Esau&#8217;s three wives representatives of different strands within the regional population. The social complexity of ancient Near Eastern family structures is preserved honestly in the genealogical record. The biblical text does not idealize the families of the patriarchs or their connections; it records what happened. The same honesty marks the NT: James and John asked for the chief seats (Matt 20:20-21); Peter denied Christ three times (Luke 22:61). The covenant community&#8217;s history is recorded with pastoral realism, not hagiography.</p>",
"26": "<p>The sons of Dishon: Hemdan, Eshban, Ithran, and Keran. The enumeration of Horite families continues with the same care as the Edomite enumeration. The inclusion of the Horites within the Edomite chapter reflects the social reality of Esau&#8217;s settlement in Seir: he did not arrive in an empty land but in a land with existing communities. The displacement of the Horites by Esau&#8217;s descendants was a process of gradual absorption and assimilation as much as conquest. The organic growth of communities through intermarriage, economic integration, and gradual displacement is the normal mechanism of ancient social change &#8212; and divine providence works within it, not against it.</p>",
"27": "<p>The sons of Ezer: Bilhan, Zaavan, and Akan. The Horite genealogy approaches its end &#8212; three more names in the record of the displaced indigenous people of Seir. The care with which these names are preserved reflects the biblical conviction that human identity matters to God regardless of covenant status. The God who counts the hairs of every head (Luke 12:7) is the God who preserves Bilhan, Zaavan, and Akan in the text of Scripture. The gospel that Christ brings is not only for those with historical claim to the covenant but for every person whose name is recorded somewhere &#8212; including names recorded only in a genealogy that most readers skip.</p>",
"28": "<p>The sons of Dishan: Uz and Aran. Uz &#8212; the same name as the land of Uz where Job lived (Job 1:1). The connections between the patriarchal narratives and the wisdom literature run through genealogical names: Eliphaz (Job&#8217;s friend) is Esau&#8217;s son (v11); Uz (Job&#8217;s homeland) appears as a Horite name here. The wisdom tradition that Job represents has roots in the populations of the Edomite region &#8212; wisdom as a form of general revelation available to those outside the covenant community. The wisdom of Uz and the suffering of Job are part of the same regional tradition that God uses to teach his people about suffering, righteousness, and divine sovereignty. Christ answers Job&#8217;s questions not by explanation but by resurrection (1 Cor 15:20).</p>",
"29": "<p>The Horite chiefs: Lotan, Shobal, Zibeon, Anah, Dishon, Ezer, and Dishan. The summary of the Horite chiefs parallels the summary of the Edomite chiefs (vv15-19). The parallel structure of the two lists &#8212; both organized as chiefs of a people, both presented with the same genealogical formula &#8212; gives the Horites a dignity equal to the Edomites in the text&#8217;s presentation. The God who orders all nations orders both the covenant-adjacent (Edomites) and the fully outside (Horites) with the same providential care. The gospel is for all nations precisely because all nations are known to the God who orders them: &#8220;all authority in heaven and on earth has been given to me. Therefore go and make disciples of all nations&#8221; (Matt 28:18-19).</p>",
"30": "<p>&#8220;These were the Horite chiefs, according to their divisions, in the land of Seir.&#8221; The Horite section closes with the same formula as the Edomite section: enumerated, organized, summarized. The land that the Horites occupied has now been defined as Seir &#8212; which is also Edom. The overlap of names for the same territory (Seir = Edom = the hill country of the rejected line) reinforces that Esau&#8217;s settlement was a displacement, not a discovery. The covenant people will also be a displacing presence in Canaan &#8212; the same dynamic, with covenant authorization. The territorial dimensions of God&#8217;s ordering of humanity are resolved eschatologically in the new creation, where &#8220;the nations will walk by [the Lamb&#8217;s] light&#8221; (Rev 21:24).</p>",
"31": "<p>&#8220;These were the kings who reigned in Edom before any Israelite king reigned.&#8221; The kings of Edom precede the kings of Israel &#8212; Edom is politically mature before Israel has a monarchy. The anticipatory reference to the Israelite king &#8212; a king not yet on the horizon in the narrative (Jacob&#8217;s sons are not kings) &#8212; points ahead to the Davidic monarchy. The kings of Edom who reign before Israel had a king are the foil against which the Davidic kingship will be measured. And the Davidic kingship is itself the foil against which the messianic king is measured (Isa 9:6-7; Luke 1:32-33). The Edomite kings list, read in this trajectory, points toward the one King whose kingdom will have no end.</p>",
"32": "<p>Bela son of Beor became king of Edom. Bela son of Beor &#8212; the identical name-pattern as Balaam son of Beor (Num 22:5), the prophet hired to curse Israel. Whether this is coincidence or a connection, the association of the name &#8220;Beor&#8221; with both the first Edomite king and the hired prophet who was compelled to bless Israel instead of curse (Num 23:8) is suggestive. The God who turns the curser&#8217;s mouth into blessing (Num 23:20) is the God who will ultimately turn Edom&#8217;s enmity into reconciliation. The messianic prophecy of Num 24:17 &#8212; &#8220;a star will come out of Jacob; a scepter will rise out of Israel. It will crush the foreheads of Moab, the skulls of all the people of Sheth&#8221; &#8212; comes from the mouth of a man named like this first Edomite king.</p>",
"33": "<p>Jobab son of Zerah from Bozrah succeeded Bela as king. Bozrah &#8212; the prominent Edomite city that appears in prophetic literature as the emblem of Edom&#8217;s pride and the object of divine judgment. Isa 63:1 &#8212; &#8220;Who is this coming from Edom, from Bozrah, with his garments stained crimson? Who is this, robed in splendor, striding forward in the greatness of his strength?&#8221; &#8212; the divine warrior coming from Bozrah in judgment. In Amos 1:12 and Isa 34:6, Bozrah is the site of divine judgment on Edom. The city that provides the second Edomite king also provides the setting for one of the most vivid images of divine redemptive judgment in the prophets &#8212; an image that Rev 19:13 applies to Christ (&#8220;he is dressed in a robe dipped in blood&#8221;).</p>",
"34": "<p>Husham from the land of the Temanites succeeded Jobab as king. Teman &#8212; the wisdom center of Edom (v11, v15), the homeland of Eliphaz the Temanite of Job, the city whose wisdom Jer 49:7 eulogizes. A king from Teman brings the wisdom tradition of Edom to the throne. The covenant people are not the only source of human wisdom &#8212; but their wisdom, grounded in the fear of the LORD (Prov 1:7), is distinctive. The wisdom of Teman was real; the wisdom that could not save Edom was not wrong but incomplete. Christ as the one in whom &#8220;are hidden all the treasures of wisdom and knowledge&#8221; (Col 2:3) is the completion of all partial wisdoms &#8212; including Teman&#8217;s.</p>",
"35": "<p>Hadad son of Bedad, who defeated Midian in Moab, succeeded Husham as king. The first Edomite king with a military achievement recorded: the defeat of Midian in Moab. The Edomite kingdom is strong enough to project power into neighboring territories. The irony that Hadad&#8217;s military victory is the one historical note in the Edomite king list: the covenant people&#8217;s victories are recorded in the context of divine deliverance; the Edomite victory is recorded as the king&#8217;s own achievement. The difference between the theology of military success in Deuteronomy (&#8220;it is not by your own sword and bow&#8221; &#8212; Josh 24:12) and the Edomite attribution of military success to the king is the difference between covenant and non-covenant historiography.</p>",
"36": "<p>Samlah from Masrekah succeeded Hadad as king. The succession of Edomite kings without dynastic continuity &#8212; each new king comes from a different city and apparently a different family &#8212; contrasts with the Davidic covenant promise of dynastic permanence (2 Sam 7:12-16: &#8220;your house and your kingdom will endure forever before me&#8221;). The Edomite kingship is elective or competitive, not dynastic. The messianic promise is dynastic and eternal &#8212; a king not like the Edomite kings who come and go, but one whose throne endures forever. The contrast between the succession list of Edom and the genealogy of the Davidic line points toward the one king who is also the eternal Son (Ps 2:7; Heb 1:5).</p>",
"37": "<p>Shaul from Rehoboth on the river succeeded Samlah as king. Rehoboth &#8212; a place-name meaning &#8220;broad places&#8221; or &#8220;room.&#8221; The same name appears in Isaac&#8217;s well-digging narrative (26:22): &#8220;Now the LORD has given us room, and we will flourish in the land.&#8221; The covenant promise of space/room for the covenant people contrasts with the king of Rehoboth &#8220;on the river&#8221; (possibly the Euphrates) &#8212; an Edomite king from a boundary territory. The &#8220;room&#8221; that Isaac celebrated as divine gift is here the name of a king&#8217;s city. The providential provision of room for the covenant people has an analogue in the territorial prosperity of Edom, even without the covenant. Common grace provides room for all; the covenant provides the meaning of that room.</p>",
"38": "<p>Baal-Hanan son of Akbor succeeded Shaul as king. &#8220;Baal-Hanan&#8221; &#8212; a name that includes the name of the Canaanite fertility god, Baal. The Edomite king whose name invokes Baal is a window into the religious world of the surrounding nations &#8212; the same Baal worship that will be the greatest internal temptation for Israel (1 Kgs 18-19; Elijah vs. the prophets of Baal). The covenant people&#8217;s vulnerability to Baal worship was always related to their proximity to the nations whose kings were named after Baal. Christ as the Lord who conquers Baal &#8212; not by Elijah&#8217;s fire from heaven but by the definitive victory of the resurrection &#8212; is the answer to the long Baal problem in Israel&#8217;s history.</p>",
"39": "<p>Hadad succeeded Baal-Hanan and his wife was Mehetabel, daughter of Matred, daughter of Me-zahab. The last king in the pre-Israelite list &#8212; and the one whose wife&#8217;s lineage is noted, the only such notation in the list. Me-zahab means &#8220;waters of gold&#8221; &#8212; a name suggestive of luxury or wealth. The final Edomite king&#8217;s wife comes from a named lineage, giving her a dignity that the other queens are not given. The listing of the woman&#8217;s lineage alongside the king&#8217;s reflects the biblical pattern of honoring women within genealogical records. Ruth, Tamar, Rahab, and Bathsheba are named in Christ&#8217;s genealogy (Matt 1:3-6); the women of Edom&#8217;s royal line receive their record here.</p>",
"40": "<p>The chiefs of Esau by name and clan &#8212; a second list of chiefs (the first was in vv15-19) organized differently, apparently by territorial region rather than family descent. Chiefs Timna, Alvah, Jetheth &#8212; the first three of eleven chiefs in vv40-43. The double listing &#8212; first by family (vv15-19), then by territory (vv40-43) &#8212; shows the two organizing principles of tribal society: kinship and land. The covenant community also organized by both tribe (kinship) and allotted territory (the land of Canaan divided among the twelve tribes in Josh 13-19). The organizational patterns of all human communities reflect the basic realities of family and land &#8212; both of which find their eschatological fulfillment in the family of God and the new earth (Rev 21:1-4).</p>",
"41": "<p>Chiefs Oholibamah, Elah, Pinon &#8212; three more Edomite territorial chiefs. The name Oholibamah appears both as one of Esau&#8217;s wives (v2) and as a territorial chief here &#8212; likely named after the woman who founded the family. The naming of territories after founding mothers is a form of memorial that the biblical text preserves without embarrassment. The women whose names become place-names in Edom are not the mothers of the covenant promise, but they are the mothers of real human communities. The God who knows the number of hairs on every head (Luke 12:7) knows Oholibamah&#8217;s name and the community she founded. Her memorial is in Scripture.</p>",
"42": "<p>Chiefs Kenaz, Teman, Mibzar &#8212; including Teman and Kenaz, which were also names of Eliphaz&#8217;s sons (v11). The overlap of personal names and territorial/clan names shows the fluid relationship between genealogy and geography in ancient Israelite record-keeping: a region often takes its name from a founding ancestor, or a person&#8217;s name becomes identified with the region they inhabited. Kenaz &#8212; a name also carried by Caleb&#8217;s ancestor among the Israelites (Num 32:12: &#8220;Caleb son of Jephunneh the Kenizzite&#8221;) &#8212; appears in both Edomite and Israelite lineages. The overlap of names across covenant and non-covenant communities is a reminder that the covenant people were drawn from the same human pool as those outside the covenant.</p>",
"43": "<p>&#8220;Magdiel and Iram. These were the chiefs of Edom, according to their settlements in the land they occupied. This was Esau the father of the Edomites.&#8221; The final verse of ch36 closes the Edomite record with its territorial summary and the identifying phrase &#8220;Esau the father of the Edomites.&#8221; From Genesis 36 onward, the narrative leaves Edom and follows Jacob&#8217;s family &#8212; beginning immediately in 37:1 with &#8220;Jacob lived in the land where his father had stayed, the land of Canaan.&#8221; The transition from Esau to Jacob &#8212; from the rejected line to the covenant line &#8212; marks the movement toward the Joseph narrative and through it toward the Exodus, Sinai, and ultimately Christ. Ch36 is the door that closes on one story so the main story can continue.</p>"
},
"37": {
"1": "<p>&#8220;Jacob lived in the land where his father had stayed, the land of Canaan.&#8221; The covenant heir in the covenant land &#8212; immediately after the closing of Esau&#8217;s chapter. The contrast is deliberate: Esau settled in Seir; Jacob settled in Canaan. The land of promise is occupied by the covenant heir. The Joseph narrative begins from this settled, covenantal location: Jacob in Canaan, which is where the promise places him. The stable foundation of covenant location is about to be disrupted by the providential descent of Joseph into Egypt &#8212; the disruption that will ultimately bring the whole family down, setting up the Exodus redemption. The peaceful opening of v1 contrasts with the turmoil that follows.</p>",
"2": "<p>&#8220;This is the account of Jacob&#8217;s family line. Joseph, a young man of seventeen, was tending the flocks with his brothers.&#8221; The <em>toledot</em> of Jacob begins &#8212; but it is immediately about Joseph, not Jacob. Jacob&#8217;s story is told through his son. The father&#8217;s narrative is carried by the son&#8217;s life. The divine covenant purpose for the family runs through the son who will be rejected and exalted. John 5:19 &#8212; &#8220;the Son can do nothing by himself; he can only do what he sees his Father doing, because whatever the Father does the Son also does.&#8221; Joseph as the son who carries the father&#8217;s narrative is the type of the Son who carries the Father&#8217;s redemptive purpose. The &#8220;bad report&#8221; Joseph brings anticipates the prophet&#8217;s role &#8212; and the rejection that comes with it.</p>",
"3": "<p>&#8220;Now Israel loved Joseph more than any of his other sons, because he had been born to him in his old age; and he made an ornate robe for him.&#8221; The beloved son, distinguished by a special garment. Matt 3:17 &#8212; &#8220;This is my Son, whom I love; with him I am well pleased&#8221; &#8212; the Father&#8217;s public declaration of the beloved Son at the baptism. The ornate robe (<em>kutonet passim</em> &#8212; the same garment given to Tamar, 2 Sam 13:18, a royal garment) is the visible marker of Joseph&#8217;s favored status. The stripping of the robe in v23 parallels the stripping of Jesus&#8217; garments at the crucifixion (John 19:23-24: &#8220;they took his clothes, dividing them into four shares&#8221;). The robe given by the father is taken by the brothers who reject him.</p>",
"4": "<p>&#8220;When his brothers saw that their father loved him more than any of them, they hated him and could not say a kind word to him.&#8221; The hatred that arises from perceived preferential love &#8212; the brothers&#8217; resentment of the beloved son. John 15:25 &#8212; &#8220;they hated me without reason.&#8221; The hatred of the covenant community for the one who is distinctively loved by the Father: the religious leaders&#8217; hatred of Jesus is rooted in the same jealousy that drives the brothers &#8212; the recognition that his relationship with God the Father is different in kind from theirs (John 5:18: &#8220;he was even calling God his own Father, making himself equal with God&#8221;). The inability to &#8220;say a kind word&#8221; anticipates the rejection of Christ&#8217;s words: &#8220;he was in the world, and though the world was made through him, the world did not recognize him&#8221; (John 1:10).</p>",
"5": "<p>Joseph told his brothers his dream, and they hated him all the more. The dream that reveals Joseph&#8217;s future authority is the message that intensifies the rejection. The more clearly the beloved son&#8217;s future glory is revealed, the more his brothers hate him. The Transfiguration (Matt 17:1-9) reveals Christ&#8217;s glory and is immediately followed by the descent into the valley and the movement toward Jerusalem and the cross. The revelation of glory does not prevent rejection; in the case of Joseph and Christ, it provokes it. The brothers who cannot tolerate the dream of future lordship are the type of those who &#8220;took offense&#8221; at Jesus (Matt 13:57).</p>",
"6": "<p>&#8220;He said to them, &#8216;Listen to this dream I had.&#8217;&#8221; Joseph shares the prophetic dream freely, without apparent awareness of the provocation it creates. The innocent sharing of revealed truth &#8212; the prophetic word that does not calculate its reception but simply speaks. The prophet Isaiah speaks without calculating whether the people will hear (Isa 6:9-10 &#8212; &#8220;be ever hearing, but never understanding&#8221;). Christ speaks in parables partly to reveal and partly to conceal (Matt 13:11-15), but his basic posture is to speak freely. The servant&#8217;s role is to speak what has been revealed; the reception is not the servant&#8217;s responsibility. John 12:49 &#8212; &#8220;I did not speak on my own, but the Father who sent me commanded me to say all that I have spoken.&#8221;</p>",
"7": "<p>&#8220;We were binding sheaves in the field when suddenly my sheaf rose and stood upright, while your sheaves gathered around mine and bowed down to it.&#8221; The first dream: agricultural imagery of future lordship. The bowing sheaves are the sign of the coming reversal &#8212; the rejected one will be the one to whom all must come. Phil 2:9-11 &#8212; &#8220;therefore God exalted him to the highest place and gave him the name that is above every name, that at the name of Jesus every knee should bow.&#8221; The bowing sheaves of Joseph&#8217;s dream are the type of the universal submission that Christ&#8217;s exaltation inaugurates. The dream is prophecy &#8212; and the prophecy will be fulfilled when the brothers bow before Joseph in Egypt (42:6).</p>",
"8": "<p>&#8220;Do you intend to reign over us? Will you actually rule us?&#8221; The brothers&#8217; enraged reading of the dream &#8212; they understand it correctly. The rejected question of the beloved son&#8217;s lordship: &#8220;Will you actually rule us?&#8221; Luke 19:14 &#8212; in the parable of the minas, the citizens send a delegation saying &#8220;we don&#8217;t want this man to be our king.&#8221; The question of the brothers is the question of every heart that encounters Christ: will you submit to his lordship? The rejection of that lordship was the driving motive of the crucifixion (John 19:15: &#8220;we have no king but Caesar&#8221;) and the driving resistance of every human heart to the gospel (Rom 8:7: &#8220;the sinful mind is hostile to God&#8221;).</p>",
"9": "<p>The second dream: the sun, moon, and eleven stars bowing to Joseph. The cosmic imagery &#8212; sun, moon, stars &#8212; elevates the scope from agricultural (sheaves) to universal (the lights of creation). The two dreams are the prophetic double-witness: Pharaoh&#8217;s butler and baker, Pharaoh&#8217;s two dreams. The pattern of double witness to the same truth &#8212; Joseph&#8217;s lordship will be universal. The cosmic imagery of Rev 12:1 &#8212; &#8220;a great sign appeared in heaven: a woman clothed with the sun, with the moon under her feet and a crown of twelve stars on her head&#8221; &#8212; repurposes the same sun/moon/twelve-star imagery for the covenant community (Israel/Church) as the one who bears the Messiah. The dreams of Joseph converge with the vision of Revelation in their cosmic scope.</p>",
"10": "<p>Jacob rebukes Joseph: &#8220;What is this dream you had? Will your mother and I and your brothers actually come and bow down to the ground before you?&#8221; The father who rebukes the dream he does not yet understand &#8212; and then keeps it in mind (v11). The father&#8217;s rebuke does not nullify the revelation; it keeps it in tension with present reality. Mary&#8217;s response to Gabriel &#8212; &#8220;how will this be?&#8221; (Luke 1:34) &#8212; and her treasuring of the angel&#8217;s words (Luke 2:19, 51) are the pattern: the parent who receives the promise about the son, does not fully understand it, and keeps it. Jacob keeps the matter in mind; the matter will be kept until Egypt vindicates the dream.</p>",
"11": "<p>&#8220;His brothers were jealous of him, but his father kept the matter in mind.&#8221; The two responses to the prophetic revelation: jealousy (the brothers) and pondering (the father). The jealousy that the revelation of Christ&#8217;s glory provokes in those who compete for human honor &#8212; the scribes and Pharisees who &#8220;were looking for a way to arrest Jesus&#8221; (Matt 26:3-4) because the crowds followed him. The pondering that Mary exemplifies (Luke 2:19, 51) &#8212; holding the revelation without full comprehension, trusting that it will be understood. The faithful response to divine revelation that exceeds current comprehension is to keep it in mind, not to deny it or demand instant fulfillment.</p>",
"12": "<p>Joseph&#8217;s brothers went to graze the flocks at Shechem &#8212; away from their father. The brothers without the father&#8217;s oversight, in the place where violence had previously occurred (the Dinah incident, ch34). The ominous geography: Shechem as the place of trouble. The father sending the son into a situation where the brothers are unsupervised and potentially dangerous &#8212; the vulnerability of the beloved son in the hands of those who have already declared their hatred. The father&#8217;s trust (v13: &#8220;I am going to send you to them&#8221;) against the brothers&#8217; plotted treachery is the frame of the entire redemptive transaction. The Son sent into the world by the Father (John 3:16) enters a world that has already declared its hostility (John 1:11).</p>",
"13": "<p>&#8220;Come, I am going to send you to them.&#8221; &#8220;Very well,&#8221; Joseph replied. The father&#8217;s sending and the son&#8217;s willing response &#8212; the double movement of incarnation. John 6:38 &#8212; &#8220;I have come down from heaven not to do my will but to do the will of him who sent me.&#8221; John 17:3 &#8212; &#8220;the only true God, and Jesus Christ, whom you have sent.&#8221; The &#8220;go and see how your brothers are&#8221; mission of Joseph is the type of the Son&#8217;s mission to the lost sheep of Israel (Matt 15:24): the father sends, the son goes. The willing response &#8212; Joseph&#8217;s simple &#8220;very well&#8221; &#8212; is the type of Gethsemane&#8217;s &#8220;not my will, but yours be done&#8221; (Luke 22:42).</p>",
"14": "<p>Jacob sends Joseph from the Valley of Hebron toward Shechem. Hebron &#8212; where Abraham and Isaac were buried, the center of the covenant patrimony &#8212; is the departure point. The beloved son leaves the place of the covenant promise to seek the brothers who have rejected him. The departure from Hebron toward Shechem is the beginning of the descent: Hebron → Shechem → Dothan → the cistern → Egypt. Each step takes Joseph further from the covenant land and deeper into the place of humiliation. Phil 2:7-8 &#8212; &#8220;he made himself nothing, taking the very nature of a servant&#8230; he humbled himself by becoming obedient to death &#8212; even death on a cross.&#8221; The descent of Joseph is the type of the kenotic descent of Christ.</p>",
"15": "<p>Joseph wandered in the fields and a man found him. The anonymous man who redirects Joseph to Dothan &#8212; the providential stranger whose brief intervention changes the course of the narrative. The stranger who asks &#8220;what are you looking for?&#8221; (the same question the risen Jesus asks, John 20:15: &#8220;woman, why are you crying? Who is it you are looking for?&#8221;) is the anonymous instrument of divine providence. The Joseph narrative is full of such providential strangers: the unnamed man of v15, the cupbearer who forgets and then remembers (40:23, 41:9), the Midianite merchants who happen to pass (v25). Divine providence operates through ordinary, anonymous human actions that are remembered in retrospect as the path God prepared.</p>",
"16": "<p>&#8220;I&#8217;m looking for my brothers.&#8221; Joseph&#8217;s answer &#8212; the beloved son seeking his brothers who have rejected him. Heb 2:11 &#8212; &#8220;both the one who makes people holy and those who are made holy are of the same family. So Jesus is not ashamed to call them brothers.&#8221; The Christ who seeks his brothers &#8212; who comes looking for them even after they have rejected him &#8212; is the one prefigured in Joseph&#8217;s search. The seeking love of the shepherd who leaves the ninety-nine (Luke 15:4), the woman who sweeps the house for the lost coin (Luke 15:8), the father who runs to meet the returning son (Luke 15:20) &#8212; all these parables describe the seeking movement of divine love that Joseph&#8217;s journey embodies.</p>",
"17": "<p>&#8220;They have moved on from here&#8230; Let&#8217;s go to Dothan.&#8221; The brothers have moved &#8212; Joseph follows to Dothan. The persistent pursuit of the beloved son after the brothers who keep moving away. The God who pursues his people through wilderness, exile, and dispersion &#8212; &#8220;where can I flee from your presence?&#8221; (Ps 139:7). Dothan is also the place where Elisha&#8217;s servant will see the divine army surrounding the city (2 Kgs 6:13-17): &#8220;those who are with us are more than those who are with them.&#8221; The place where Joseph will be thrown into the cistern is the same place where the divine army will be revealed to protect Elisha. God is at work in Dothan both times &#8212; once through apparent abandonment, once through visible protection.</p>",
"18": "<p>&#8220;Before he reached them, they plotted to kill him.&#8221; The brothers&#8217; conspiracy against the beloved son &#8212; seen &#8220;in the distance,&#8221; recognized, and immediately targeted. The distance at which the conspiracy is formed: they see him coming and begin plotting before he arrives. Matt 26:3-4 &#8212; &#8220;the chief priests and the elders of the people assembled in the palace of the high priest, and they schemed to arrest Jesus secretly and kill him.&#8221; The conspiracy that precedes the victim&#8217;s arrival is the pattern of both Joseph and Christ: the rejection is not reactive but premeditated, not provoked by a specific offense but by the fact of who he is &#8212; the beloved, the chosen, the one whose dreams threaten their self-determination.</p>",
"19": "<p>&#8220;Here comes that dreamer!&#8221; (<em>baʿal haḥălōmōt</em> &#8212; &#8220;lord of dreams&#8221;). The contemptuous title &#8212; mocking the very gift that makes Joseph dangerous to them. The title they use in mockery will be vindicated by the narrative. The mocking titles at the cross &#8212; &#8220;he saved others; let him save himself&#8221; (Luke 23:35), &#8220;King of the Jews&#8221; (Matt 27:37 &#8212; written as a title of mockery, standing as an eternal truth). The titles meant to humiliate become the titles that endure. &#8220;Lord of dreams&#8221; is exactly what Joseph is &#8212; the one to whom God reveals his plans, the interpreter of the divine purpose hidden in the night visions of kings. The brothers&#8217; mockery is their most accurate statement about him.</p>",
"20": "<p>&#8220;Come now, let&#8217;s kill him and throw him into one of these cisterns and say that a ferocious animal devoured him. Then we&#8217;ll see what comes of his dreams.&#8221; The wicked tenants&#8217; logic made explicit: kill the beloved son so his dreams do not come true &#8212; so his claim to rule will be nullified by death. Matt 21:38 &#8212; &#8220;this is the heir. Come, let&#8217;s kill him and take his inheritance.&#8221; The conspiracy to destroy the dreams by destroying the dreamer is the conspiracy to end the kingdom by killing the king. &#8220;Then we&#8217;ll see what comes of his dreams&#8221; is the brothers&#8217; version of &#8220;let him come down from the cross, and we will believe in him&#8221; (Matt 27:42). The challenge to death is answered by resurrection: the dreams survive the death of the dreamer.</p>",
"21": "<p>Reuben tried to rescue Joseph from his brothers: &#8220;Let&#8217;s not take his life.&#8221; Reuben &#8212; the firstborn who lost his birthright through immorality (35:22; 49:4) &#8212; intervenes for Joseph. The flawed eldest brother who cannot prevent the injustice but attempts to mitigate it: the type of Pilate (Matt 27:24: &#8220;I am innocent of this man&#8217;s blood&#8221;) or of Nicodemus (John 7:50-51: &#8220;does our law condemn a man without first hearing him?&#8221;) &#8212; the insider who recognizes the injustice but cannot stop it. The ineffective advocate who registers dissent without being able to reverse the conspiracy is a recurring figure in both testaments. The only effective advocate is Christ himself (1 John 2:1: &#8220;we have an advocate with the Father &#8212; Jesus Christ, the Righteous One&#8221;).</p>",
"22": "<p>&#8220;Throw him into this cistern here in the wilderness, but don&#8217;t lay a hand on him.&#8221; Reuben&#8217;s plan to rescue Joseph from the cistern later. The cistern (<em>bôr</em> &#8212; pit/cistern/dungeon) as the place of apparent abandonment that is actually a place of divine protection. The Hebrew word <em>bôr</em> is also used for the dungeon where Joseph will later be imprisoned (40:15: &#8220;they put me in the pit&#8221;) and in Psalm 16:10 (&#8220;you will not abandon me to the realm of the dead, nor will you let your faithful one see decay&#8221; &#8212; Peter applies this to Christ in Acts 2:27-31). The cistern is the type of the tomb: the place of apparent death and abandonment that turns out to be temporary, from which the beloved son emerges.</p>",
"23": "<p>They stripped Joseph of his robe &#8212; the ornate robe his father had made. The robe given by the father is taken by the brothers. The stripping of the beloved son&#8217;s garment &#8212; the visible sign of the father&#8217;s love &#8212; is the act of rejection made physical. John 19:23-24 &#8212; the soldiers at the cross divide Jesus&#8217; clothes and cast lots for his tunic, fulfilling Ps 22:18 (&#8220;they divide my clothes among them and cast lots for my garment&#8221;). The stripping of Joseph&#8217;s robe is the type of the stripping of Christ&#8217;s garments: in both cases the beloved son is stripped of his kingly dignity by those who reject his lordship. The robe will be dipped in blood (v31); Christ&#8217;s garments will also be associated with blood (John 19:2 &#8212; the crown of thorns; Isa 63:1-3).</p>",
"24": "<p>&#8220;They took him and threw him into the cistern. Now the cistern was empty; there was no water in it.&#8221; The empty cistern &#8212; no water, and therefore no drowning. The cistern that receives Joseph is not the instrument of death but the holding place that preserves him for rescue. The tomb that receives Christ is similarly empty of the power of permanent death &#8212; it is a holding place from which he emerges (John 20:1-10). The narrative&#8217;s parenthetical note &#8212; &#8220;there was no water in it&#8221; &#8212; is the detail that ensures the reader knows Joseph is alive in the cistern. The parallel: &#8220;the tomb was empty&#8221; is the detail that ensures the reader knows Christ is risen. The empty cistern and the empty tomb are structurally identical narrative moments.</p>",
"25": "<p>&#8220;As they sat down to eat their meal&#8221; &#8212; the brothers eat while Joseph is in the cistern. The casual cruelty of those who have consigned the beloved son to the pit and then sit down to eat. 1 Cor 11:29 &#8212; eating the Lord&#8217;s Supper without recognizing &#8220;the body of the Lord.&#8221; The meal eaten in the presence of suffering and abandonment is the anti-type of the Lord&#8217;s Supper &#8212; the meal eaten in conscious remembrance of the one who was cast down and raised. The Ishmaelite caravan coming from Gilead &#8212; the same route that will become the exile route (Jer 8:22: &#8220;is there no balm in Gilead?&#8221;) &#8212; is the providential interruption that changes Joseph&#8217;s trajectory from death to Egypt.</p>",
"26": "<p>&#8220;What will we gain if we kill our brother and cover up his blood?&#8221; Judah&#8217;s pragmatic argument against murder. Judah &#8212; the ancestor of the tribe through whom Christ comes (Matt 1:2-3; Rev 5:5: &#8220;the Lion of the tribe of Judah&#8221;) &#8212; is the one who proposes the sale of Joseph. The name Judah (<em>Yehudah</em>) and Judas (<em>Ioudas</em>) are the same name across the testaments. The one who proposes selling the beloved son for silver is the type of the one who sells the Messiah for thirty pieces of silver (Matt 26:15). The Judah/Judas connection is one of the most explicit typological correspondences in the Joseph narrative: the ancestor of Christ&#8217;s tribe is also the one who initiates his type&#8217;s betrayal into slavery.</p>",
"27": "<p>&#8220;Come, let&#8217;s sell him to the Ishmaelites and not lay our hands on him; after all, he is our brother, our own flesh and blood.&#8221; Judah&#8217;s argument: sell rather than kill, because &#8220;he is our brother.&#8221; The acknowledgment of brotherhood that nonetheless does not prevent the betrayal. The disciples who ate at the table with Jesus (John 13:18: &#8220;he who shared my bread has turned against me&#8221;) knew him as their Lord and still betrayed him. The covenant familiarity &#8212; &#8220;he is our brother&#8221; &#8212; does not prevent the betrayal; it makes the betrayal more acute. Ps 41:9 &#8212; &#8220;even my close friend, someone I trusted, one who shared my bread, has turned against me&#8221; &#8212; the betrayal by the familiar is the most painful kind.</p>",
"29": "<p>Reuben returned to the cistern and found Joseph gone &#8212; he tore his clothes. The firstborn&#8217;s grief at the empty cistern &#8212; the one who had planned to rescue Joseph and now finds him gone. The anguish of finding the cistern empty: Reuben&#8217;s tearing of clothes is the grief of failure, of having been unable to prevent the irreversible. The women who came to the tomb on Easter morning and found it empty &#8212; but their empty-tomb experience is grief turning to joy, not grief deepening. Reuben&#8217;s anguish at the empty cistern is the human response before the resurrection reversal: the beloved son is gone, and it seems like permanent loss. Easter inverts the empty-cistern experience: the empty tomb is not tragedy but triumph.</p>",
"30": "<p>&#8220;The boy isn&#8217;t there! Where can I turn now?&#8221; Reuben&#8217;s cry &#8212; the despair of the one who sought to protect the beloved son and failed. &#8220;Where can I turn?&#8221; is the cry of those who discover that the one they trusted to save has apparently been lost. The disciples on Holy Saturday: &#8220;we had hoped that he was the one who was going to redeem Israel&#8221; (Luke 24:21 &#8212; the Emmaus road confession of lost hope). The empty cistern produces the same hopeless disorientation as the cross: the beloved son gone, and no one knows where to turn. The answer to &#8220;where can I turn?&#8221; is the same in both testaments: he was not left in the cistern/tomb, and the dreams/resurrection are the proof.</p>",
"31": "<p>The brothers slaughtered a goat and dipped Joseph&#8217;s robe in the blood. The false evidence &#8212; the bloody robe that will convince Jacob his son is dead. The substitution of the innocent animal&#8217;s blood for the beloved son&#8217;s blood is the inverse of the sacrifice: instead of the animal dying so the beloved son lives (Gen 22:13 &#8212; the ram instead of Isaac), here the animal dies to provide the blood that makes it appear the beloved son is dead. The robe dipped in blood is the false testimony &#8212; the lie told by the brothers who want to hide their guilt. The irony: a robe dipped in blood (Christ&#8217;s) is in Revelation the sign of the warrior-king&#8217;s victory (Rev 19:13), not his death.</p>",
"32": "<p>&#8220;We found this. Examine it to see whether it is your son&#8217;s robe.&#8221; The brothers present the evidence to Jacob without directly lying &#8212; &#8220;we found this&#8221; is technically true; &#8220;examine it yourself&#8221; lets Jacob draw the false conclusion. The careful deception that avoids the explicit lie while ensuring the false conclusion: the Pharisees&#8217; question to Jesus (Matt 22:15-22 &#8212; &#8220;is it right to pay the imperial tax to Caesar?&#8221;) uses the same structure &#8212; a question designed to force a false conclusion regardless of the answer. The brothers&#8217; presentation of the bloody robe is the type of false testimony at Christ&#8217;s trial (Matt 26:59-61: &#8220;the chief priests and the whole Sanhedrin were looking for false evidence against Jesus&#8221;).</p>",
"33": "<p>&#8220;It is my son&#8217;s robe! Some ferocious animal has devoured him. Joseph has surely been torn to pieces.&#8221; Jacob&#8217;s conclusion &#8212; drawn correctly from false evidence. The father who believes his son is dead &#8212; who mourns with absolute certainty that the beloved is gone. The grief of the Father who &#8220;did not spare his own Son, but gave him up for us all&#8221; (Rom 8:32) &#8212; the divine participation in the loss of the Son. The theological analogy is inexact: God knew Christ would rise; Jacob did not know Joseph lived. But the father&#8217;s grief at the apparent loss of the beloved son is the narrative form of the divine sorrow that the cross involves. Jesus&#8217; cry of dereliction (Matt 27:46: &#8220;my God, my God, why have you forsaken me?&#8221;) is the Son&#8217;s cry in the darkness of the cistern.</p>",
"34": "<p>Jacob tore his clothes, put on sackcloth, and mourned for his son many days. The father in sackcloth &#8212; the visible, embodied grief of the one who believes his beloved is gone. The covenant heir who bore the promise now mourns the apparent end of the promise-line through Joseph. The grief of Holy Saturday &#8212; the disciples in hiding, the women at the tomb, the apparent end of the movement that had promised the Kingdom. The many days of Jacob&#8217;s mourning are the type of the three days before the resurrection &#8212; the interval that feels like permanent loss but is actually the prelude to the vindication of the beloved son.</p>",
"35": "<p>&#8220;All his sons and daughters came to comfort him, but he refused to be comforted. &#8216;No,&#8217; he said, &#8216;I will continue to mourn until I join my son in the grave.&#8217;&#8221; The grief that refuses comfort because it refuses false consolation &#8212; Jacob will not be comforted by those who orchestrated the loss. The prophetic type of Rachel weeping for her children (Jer 31:15: &#8220;Rachel weeping for her children and refusing to be comforted, because they are no more&#8221; &#8212; quoted in Matt 2:18 for the slaughter of the innocents). The grief that seems inconsolable is the grief that can only be comforted by the actual return of the one lost &#8212; which is what happens in ch45. The only consolation for the loss of the beloved son is the discovery that he was not lost but went ahead to prepare the way (John 14:2-3).</p>",
"36": "<p>&#8220;Meanwhile, the Midianites sold Joseph in Egypt to Potiphar, one of Pharaoh&#8217;s officials, the captain of the guard.&#8221; The descent complete: from Canaan to the cistern to the Ishmaelites to Egypt to the household of Pharaoh&#8217;s captain. The trajectory of humiliation &#8212; beloved son, stripped of his robe, thrown in a pit, sold as a slave, property of an Egyptian official. Phil 2:7-8 &#8212; &#8220;he made himself nothing, taking the very nature of a servant, being made in human likeness. And being found in appearance as a man, he humbled himself by becoming obedient to death.&#8221; Joseph&#8217;s descent into Potiphar&#8217;s house is the lowest point before the ascent to Pharaoh&#8217;s right hand &#8212; the kenosis before the exaltation that is the shape of the gospel.</p>"
}
}

def main():
    existing = load_comm('mkt-christ', 'genesis')
    merge_comm(existing, NEW_DATA)
    save_comm('mkt-christ', 'genesis', existing)
    print(f"  ch36 verses: {len(existing.get('36', {}))}")
    print(f"  ch37 verses: {len(existing.get('37', {}))}")
    print("Genesis 36–37 mkt-christ written.")

if __name__ == '__main__':
    main()
